const input = $input.first().json;
let text = '';

if (input.body && input.body.text) {
  text = input.body.text;
} else if (input.body && input.body.url) {
  return [{ json: { text: '', url: input.body.url, mode: 'url', valid: true } }];
} else {
  return [{ json: { error: 'Provide { "text": "..." } in the request body', valid: false } }];
}

if (text.length < 20) {
  return [{ json: { error: 'Text must be at least 20 characters for meaningful extraction', valid: false } }];
}

// Cap at 6000 chars for context window
const processedText = text.substring(0, 6000);

return [{ json: { text: processedText, original_length: text.length, mode: 'text', valid: true } }];

const ollamaResponse = $input.first().json;
let responseText;

try {
  const parsed = typeof ollamaResponse.data === 'string' ? JSON.parse(ollamaResponse.data) : ollamaResponse;
  responseText = parsed.response || parsed.data?.response || '';
} catch (e) {
  responseText = JSON.stringify(ollamaResponse);
}

// Extract JSON from response
let extraction;
try {
  const jsonMatch = responseText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    extraction = JSON.parse(jsonMatch[0]);
  } else {
    extraction = { raw_extraction: responseText };
  }
} catch (e) {
  extraction = { raw_extraction: responseText };
}

const inputData = $('Validate & Prepare').first().json;

return [{
  json: {
    ...extraction,
    metadata: {
      text_length: inputData.original_length,
      model: 'llama3.1:8b',
      processed_at: new Date().toISOString()
    }
  }
}];
